import React, { useState } from "react";
import { supabase } from "../lib/supabase";

const AHM_LOGO = "data:image/png;base64,";

export default function Login() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) setError(error.message);
    setLoading(false);
  };

  return (
    <div style={styles.page}>
      <div style={styles.card}>
        <div style={styles.logoWrap}>
          <img src={AHM_LOGO} alt="AxiomHealth Management" style={styles.logo} />
        </div>
        <h1 style={styles.title}>AxiomHealth Management</h1>
        <p style={styles.subtitle}>CARE COORDINATION PORTAL</p>

        <form onSubmit={handleLogin} style={styles.form}>
          <div style={styles.fieldGroup}>
            <label style={styles.label}>EMAIL</label>
            <input
              type="email"
              placeholder="your@email.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              style={styles.input}
              required
            />
          </div>
          <div style={styles.fieldGroup}>
            <label style={styles.label}>PASSWORD</label>
            <input
              type="password"
              placeholder="••••••••"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              style={styles.input}
              required
            />
          </div>
          {error && <p style={styles.error}>{error}</p>}
          <button type="submit" style={styles.button} disabled={loading}>
            {loading ? "Signing in..." : "Sign In"}
          </button>
        </form>

        <p style={styles.footer}>Contact your director if you need access</p>
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "#F6F0EE",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontFamily: "'DM Sans', sans-serif",
    padding: "24px",
  },
  card: {
    background: "#fff",
    borderRadius: "20px",
    padding: "48px 40px",
    width: "100%",
    maxWidth: "440px",
    boxShadow: "0 4px 32px rgba(0,0,0,0.08)",
    textAlign: "center",
  },
  logoWrap: {
    display: "flex",
    justifyContent: "center",
    marginBottom: "16px",
  },
  logo: {
    width: "72px",
    height: "72px",
    objectFit: "contain",
  },
  title: {
    fontSize: "22px",
    fontWeight: "700",
    color: "#0F1117",
    margin: "0 0 6px 0",
    letterSpacing: "-0.3px",
  },
  subtitle: {
    fontSize: "11px",
    fontWeight: "600",
    letterSpacing: "2px",
    color: "#9E9E9E",
    margin: "0 0 32px 0",
  },
  form: {
    textAlign: "left",
  },
  fieldGroup: {
    marginBottom: "20px",
  },
  label: {
    display: "block",
    fontSize: "11px",
    fontWeight: "700",
    letterSpacing: "1.5px",
    color: "#555",
    marginBottom: "8px",
  },
  input: {
    width: "100%",
    padding: "14px 16px",
    borderRadius: "10px",
    border: "1.5px solid #E8E0DC",
    fontSize: "15px",
    color: "#0F1117",
    background: "#FAFAFA",
    outline: "none",
    boxSizing: "border-box",
    fontFamily: "'DM Sans', sans-serif",
    transition: "border-color 0.2s",
  },
  error: {
    color: "#D94F2B",
    fontSize: "13px",
    marginBottom: "12px",
  },
  button: {
    width: "100%",
    padding: "16px",
    background: "linear-gradient(135deg, #D94F2B, #8B1A10)",
    color: "#fff",
    border: "none",
    borderRadius: "10px",
    fontSize: "16px",
    fontWeight: "700",
    cursor: "pointer",
    marginTop: "8px",
    fontFamily: "'DM Sans', sans-serif",
    letterSpacing: "0.3px",
  },
  footer: {
    marginTop: "28px",
    fontSize: "13px",
    color: "#B0A9A6",
  },
};
